"use client"

import type React from "react"
import { createClient } from "@/lib/supabase/client"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Shield } from "lucide-react"
import Link from "next/link"
import { useRouter } from "next/navigation"
import { useState } from "react"
import { useToast } from "@/hooks/use-toast"
import HeroScene from "@/components/HeroScene"

export default function LoginPage() {
  const [email, setEmail] = useState("")
  const [password, setPassword] = useState("")
  const [isLoading, setIsLoading] = useState(false)
  const router = useRouter()
  const { toast } = useToast()

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault()
    const supabase = createClient()
    setIsLoading(true)

    try {
      const { error } = await supabase.auth.signInWithPassword({
        email,
        password,
      })
      if (error) throw error

      const {
        data: { user },
      } = await supabase.auth.getUser()

      const { data: operator } = await supabase.from("operators").select("role").eq("id", user?.id).single()

      toast({
        title: "Connexion réussie",
        description: "Bienvenue dans le système TaxiGuard",
      })

      if (operator?.role === "admin") {
        router.push("/admin")
      } else {
        router.push("/operator")
      }
    } catch (error: unknown) {
      toast({
        title: "Erreur de connexion",
        description: error instanceof Error ? error.message : "Une erreur s'est produite",
        variant: "destructive",
      })
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <div className="min-h-screen bg-[#050505] text-white selection:bg-yellow-500 selection:text-black no-scrollbar flex flex-col overflow-x-hidden">
      {/* Background 3D Scene */}
      <div className="hidden md:block fixed top-0 right-0 w-[50vw] h-full z-0 opacity-40">
        <HeroScene />
      </div>

      {/* Header (Matching landing page) */}
      <header className="absolute top-0 left-0 right-0 z-50 px-8 py-6 flex items-center justify-between max-w-7xl mx-auto w-full">
        <Link href="/" className="flex items-center gap-2">
          <span className="text-xl font-bold tracking-tight text-white hover:opacity-80 transition-opacity">
            Taxi<span className="opacity-50 font-light">Guard</span>
          </span>
          <span className="hidden md:inline-block ml-4 text-xs font-medium tracking-[0.2em] uppercase opacity-40 border-l border-white/20 pl-4">
            République du Sénégal
          </span>
        </Link>
      </header>

      <main className="flex-1 flex items-center relative z-10 max-w-7xl mx-auto w-full px-8 pt-20">
        <div className="w-full max-w-md animate-fade-in-up">
          <div className="mb-8 space-y-2">
            <h1 className="text-4xl font-bold tracking-tight">Bienvenue.</h1>
            <p className="text-gray-400">Connectez-vous pour accéder au portail de contrôle.</p>
          </div>

          <div className="glass-dark p-8 rounded-3xl border border-white/10 shadow-2xl backdrop-blur-xl">
            <form onSubmit={handleLogin} className="space-y-6">
              <div className="space-y-4">
                <div className="grid gap-2">
                  <Label htmlFor="email" className="text-sm font-medium text-gray-400 ml-1">Adresse Email</Label>
                  <Input
                    id="email"
                    type="email"
                    placeholder="operateur@example.com"
                    required
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="bg-white/5 border-white/10 h-12 rounded-xl focus:ring-yellow-500/50 focus:border-yellow-500/50 placeholder:text-gray-600"
                  />
                </div>
                <div className="grid gap-2">
                  <Label htmlFor="password" name="password-label" className="text-sm font-medium text-gray-400 ml-1">Mot de Passe</Label>
                  <Input
                    id="password"
                    type="password"
                    required
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="bg-white/5 border-white/10 h-12 rounded-xl focus:ring-yellow-500/50 focus:border-yellow-500/50 placeholder:text-gray-600"
                  />
                </div>
              </div>

              <Button
                type="submit"
                className="w-full h-12 rounded-xl bg-white text-black hover:bg-gray-200 transition-all hover:scale-[1.02] active:scale-95 duration-300 font-bold shadow-[0_0_20px_rgba(255,255,255,0.1)]"
                disabled={isLoading}
              >
                {isLoading ? "Vérification..." : "Se Connecter"}
              </Button>

              <div className="text-center pt-2">
                <Link href="/" className="text-xs text-gray-500 hover:text-white transition-colors">
                  Retour à la page d'accueil
                </Link>
              </div>
            </form>
          </div>
        </div>
      </main>

      {/* Background Ambient Glows */}
      <div className="fixed top-[-20%] right-[-10%] w-[600px] h-[600px] bg-red-600/10 blur-[120px] rounded-full pointer-events-none z-0 mix-blend-screen" />
      <div className="fixed bottom-[-20%] left-[-10%] w-[600px] h-[600px] bg-green-600/5 blur-[120px] rounded-full pointer-events-none z-0 mix-blend-screen" />
    </div>
  )
}
